import numpy as np
colorama.init(autoreset=True)
from colorama import Fore, Style

# Define constants for the board
BOARD_SIZE = 8
WHITE = 'W'
BLACK = 'B'
EMPTY = '."
KINGED_WHITE = 'w'
KINGED_BLACK = 'b'

class CheckersGame:
    def __init__(self):
        self.board = np.array([[EMPTY] * BOARD_SIZE for _ in range(BOARD_SIZE)])
        self.current_player = WHITE
        self.initialize_board()

    def initialize_board(self):
        # Place initial pieces on the board
        self.board[0, 1::2], self.board[1, ::2] = [BLACK] * 4, [BLACK] * 4
        self.board[5::-1, 1::-2], self.board[6::-1, ::2] = [WHITE] * 4, [WHITE] * 4

    def print_board(self):
        print(Fore.WHITE + Style.BRIGHT + '     A B C D E F G H')
        for i in range(BOARD_SIZE):
            row = [str(i+1)] + list(self.board[i])
            print(' '.join(row))

    def get_piece_color(self, position):
        return self.board[position[0], position[1]]

    def is_valid_move(self, start_pos, end_pos):
        # Check if the move is within bounds and on the same color row
        if not (0 <= start_pos[0] < BOARD_SIZE and 0 <= start_pos[1] < BOARD_SIZE and
                0 <= end_pos[0] < BOARD_SIZE and 0 <= end_pos[1] < BOARD_SIZE):
            return False
        if self.get_piece_color(start_pos) != self.current_player:
            return False
        # Check if the move is to an empty cell or a kinged piece's move
        if self.get_piece_color(end_pos) == EMPTY or (self.get_piece_color(end_pos) in [KINGED_WHITE, KINGED_BLACK]):
            return True
        return False

    def make_move(self, start_pos, end_pos):
        if not self.is_valid_move(start_pos, end_pos):
            print('Invalid move! Please try again.')
            return
        self.board[end_pos[0], end_pos[1]] = self.get_piece_color(start_pos)
        self.board[start_pos[0], start_pos[1]] = EMPTY
        if (end_pos[0] == 0 and self.current_player == WHITE) or (end_pos[0] == BOARD_SIZE - 1 and self.current_player == BLACK):
            # Promote piece to king
            self.board[end_pos[0], end_pos[1]] += 'K'
        self.current_player = BLACK if self.current_player == WHITE else WHITE

    def is_game_over(self):
        # Check if there are any valid moves left
        for i in range(BOARD_SIZE):
            for j in range(BOARD_SIZE):
                if self.get_piece_color((i, j)) == self.current_player and any(
                        self.is_valid_move((i, j), (x, y)) for x, y in [(i-1, j+1), (i+1, j+1), (i-1, j-1), (i+1, j-1)]:
                    return False
        return True

if __name__ == '__main__':
    game = CheckersGame()
    while not game.is_game_over():
        game.print_board()
        start_pos = input(f'Player {game.current_player}, enter move (e.g., 2A): ').upper()
        end_pos = input('Enter destination (e.g., 4C): ').upper()
        start_pos = (int(start_pos[0]) - 1, ord(start_pos[1]) - 65)
        end_pos = (int(end_pos[0]) - 1, ord(end_pos[1]) - 65)
        game.make_move(start_pos, end_pos)"}}}

